#include <iostream>
#include <iomanip>

using namespace std;

/**
 * Calculates the ticket price based on age and student status.
 * Rules:
 * - Age <= 12: $7.00
 * - Age >= 65: $8.00
 * - Else (13-64): Student ? $10.00 : $12.00
 */
double calculatePrice(int age, bool isStudent) {
    if (age <= 12) {
        return 7.00;
    } else if (age >= 65) {
        return 8.00;
    } else {
        if (isStudent) {
            return 10.00;
        } else {
            return 12.00;
        }
    }
}

int main() {
    int age;
    int studentInput;

    // Read age and student status (0 or 1)
    if (!(cin >> age >> studentInput)) {
        return 0;
    }

    bool isStudent = (studentInput == 1);

    double finalPrice = calculatePrice(age, isStudent);

    // Output formatted to 2 decimal places
    cout << fixed << setprecision(2) << finalPrice << endl;

    return 0;
}
